// purevipsgenBlackWithOptions vips_black make a black image with optional arguments
func purevipsgenBlackWithOptions(width int, height int, bands int) (vipsImageRef, error) {
	out, err := purevipsgenBlack(width, height)
	if err != nil {
		return nil, err
	}
	if bands <= 1 {
		return out, nil
	}
	values := make([]float64, bands-1)
	joined, err := purevipsgenBandjoinConst(out, values)
	if err != nil {
		clearImage(out)
		return nil, err
	}
	clearImage(out)
	return joined, nil
}

