// purevipsgenDrawCircle vips_draw_circle draw a circle on an image
func purevipsgenDrawCircle(image vipsImageRef, ink []float64, cx int, cy int, radius int) (error) {
	if ink == nil {
		ink = []float64{}
	}
	cink, _, err := convertToDoubleArray(ink)
	if err != nil {
		return err
	}
	if cink != nil {
		defer freeDoubleArray(cink)
	}
	var fn func(a0 vipsImageRef, a1 unsafe.Pointer, a2 int32, a3 int32, a4 int32, a5 int32, args ...any) int32
	registerVipsFunc(&fn, "vips_draw_circle")
	if err := fn(image, cink, int32(len(ink)), int32(cx), int32(cy), int32(radius), uintptr(0)); err != 0 {
		return handleVipsError()
	}
	return nil
}

// purevipsgenDrawCircleWithOptions vips_draw_circle draw a circle on an image with optional arguments
func purevipsgenDrawCircleWithOptions(image vipsImageRef, ink []float64, cx int, cy int, radius int, fill bool) error {
	if !fill {
		return purevipsgenDrawCircle(image, ink, cx, cy, radius)
	}
	if ink == nil {
		ink = []float64{}
	}
	cink, _, err := convertToDoubleArray(ink)
	if err != nil {
		return err
	}
	if cink != nil {
		defer freeDoubleArray(cink)
	}
	var fn func(a0 vipsImageRef, a1 unsafe.Pointer, a2 int32, a3 int32, a4 int32, a5 int32, a6 int32, args ...any) int32
	registerVipsFunc(&fn, "vips_draw_line")
	r2 := radius * radius
	for dy := -radius; dy <= radius; dy++ {
		dx := int(math.Sqrt(float64(r2 - dy*dy)))
		if err := fn(image, cink, int32(len(ink)), int32(cx-dx), int32(cy+dy), int32(cx+dx), int32(cy+dy), uintptr(0)); err != 0 {
			return handleVipsError()
		}
	}
	return nil
}

