// purevipsgenEmbed vips_embed embed an image in a larger image
func purevipsgenEmbed(in vipsImageRef, x int, y int, width int, height int) (vipsImageRef, error) {
	var out vipsImageRef
	var fn func(a0 vipsImageRef, a1 *vipsImageRef, a2 int32, a3 int32, a4 int32, a5 int32, args ...any) int32
	registerVipsFunc(&fn, "vips_embed")
	if err := fn(in, &out, int32(x), int32(y), int32(width), int32(height), uintptr(0)); err != 0 {
		return nil, handleImageError(out)
	}
	return out, nil
}

// purevipsgenEmbedWithOptions vips_embed embed an image in a larger image with optional arguments
func purevipsgenEmbedWithOptions(in vipsImageRef, x int, y int, width int, height int, extend Extend, background []float64) (vipsImageRef, error) {
	switch extend {
	case ExtendWhite:
		return vipsEmbedWithBackground(in, x, y, width, height, 255, 255, 255, 255)
	case ExtendBackground:
		if len(background) >= 3 {
			a := 255
			if len(background) > 3 {
				a = int(background[3])
			}
			return vipsEmbedWithBackground(in, x, y, width, height, int(background[0]), int(background[1]), int(background[2]), a)
		}
	}
	if len(background) > 0 {
		a := 255
		if len(background) > 3 {
			a = int(background[3])
		}
		r, g, b := 0, 0, 0
		if len(background) > 0 { r = int(background[0]) }
		if len(background) > 1 { g = int(background[1]) }
		if len(background) > 2 { b = int(background[2]) }
		return vipsEmbedWithBackground(in, x, y, width, height, r, g, b, a)
	}
	return purevipsgenEmbed(in, x, y, width, height)
}

