// purevipsgenGetpoint vips_getpoint read a point from an image
func purevipsgenGetpoint(in vipsImageRef, x int, y int) ([]float64, error) {
	var out unsafe.Pointer
	var n int
	cn := new(int32)
	var fn func(a0 vipsImageRef, a1 *unsafe.Pointer, a2 *int32, a3 int32, a4 int32, args ...any) int32
	registerVipsFunc(&fn, "vips_getpoint")
	if err := fn(in, &out, cn, int32(x), int32(y), uintptr(0)); err != 0 {
		return nil, handleVipsError()
	}
	n = int(*cn)
	result := make([]float64, n)
	copy(result, (*[1024]float64)(unsafe.Pointer(out))[:n:n])
	gFreePointer(unsafe.Pointer(out))
	return result, nil
}

