// purevipsgenHeifsaveWithOptions vips_heifsave save image in HEIF format with optional arguments
func purevipsgenHeifsaveWithOptions(in vipsImageRef, filename string, q int, bitdepth int, lossless bool, compression HeifCompression, effort int, subsampleMode Subsample, encoder HeifEncoder, keep Keep, background []float64, pageHeight int, profile string) (error) {
	cfilename := cString(filename)
	cbackground, cbackgroundLength, err := convertToDoubleArray(background)
	if err != nil {
		return err
	}
	if cbackground != nil {
		defer freeDoubleArray(cbackground)
	}
	vargs := make([]any, 0)
	if q != 50 {
		vargs = append(vargs, "Q\x00", int32(q))
	}
	if bitdepth != 12 {
		vargs = append(vargs, "bitdepth\x00", int32(bitdepth))
	}
	if lossless {
		vargs = append(vargs, "lossless\x00", int32(boolToInt(lossless)))
	}
	if compression != 0 && compression != HeifCompression(1) {
		vargs = append(vargs, "compression\x00", int32(vipsOptionEnum(compression)))
	}
	if effort != 4 {
		vargs = append(vargs, "effort\x00", int32(effort))
	}
	if subsampleMode != Subsample(0) {
		vargs = append(vargs, "subsample_mode\x00", int32(vipsOptionEnum(subsampleMode)))
	}
	if encoder != HeifEncoder(0) {
		vargs = append(vargs, "encoder\x00", int32(vipsOptionEnum(encoder)))
	}
	if keep != 0 {
		vargs = append(vargs, "keep\x00", int32(vipsOptionEnum(keep)))
	}
	if cbackground != nil {
		array := newVipsArray("[]float64", cbackground, cbackgroundLength)
		defer vipsAreaUnref(array)
		vargs = append(vargs, "background\x00", array)
	}
	if pageHeight != 0 {
		vargs = append(vargs, "page_height\x00", int32(pageHeight))
	}
	if profile != "" {
		vargs = append(vargs, "profile\x00", cString(profile))
	}
	vargs = append(vargs, uintptr(0))
	var fn func(a0 vipsImageRef, a1 string, args ...any) int32
	registerVipsFunc(&fn, "vips_heifsave")
	if err := fn(in, cfilename, vargs...); err != 0 {
		return handleVipsError()
	}
	return nil
}

