func vipsImageExtrema(in vipsImageRef, wantMax bool) (float64, int, int) {
	buf, err := purevipsgenImageWriteToMemory(in)
	if err != nil || len(buf) == 0 {
		return 0, 0, 0
	}
	width, height, bands := vipsImageWidth(in), vipsImageHeight(in), vipsImageBands(in)
	if width <= 0 || height <= 0 || bands <= 0 {
		return 0, 0, 0
	}
	limitBands := bands
	if bands == 4 {
		limitBands = 3
	}
	best := float64(buf[0])
	bestX, bestY := 0, 0
	for y := 0; y < height; y++ {
		for x := 0; x < width; x++ {
			offset := (y*width + x) * bands
			if offset+limitBands > len(buf) {
				continue
			}
			var sum int
			for b := 0; b < limitBands; b++ {
				sum += int(buf[offset+b])
			}
			v := float64(sum) / float64(limitBands)
			if (wantMax && v >= best) || (!wantMax && v < best) {
				best, bestX, bestY = v, x, y
			}
		}
	}
	return best, bestX, bestY
}

func purevipsgenThumbnailImagePure(in vipsImageRef, width int, height int, crop Interesting) (vipsImageRef, error) {
	srcW, srcH := vipsImageWidth(in), vipsImageHeight(in)
	if srcW <= 0 || srcH <= 0 || width <= 0 {
		return purevipsgenCopy(in)
	}
	targetH := height
	if targetH <= 0 {
		targetH = int(math.Round(float64(srcH) * float64(width) / float64(srcW)))
	}
	scaleX := float64(width) / float64(srcW)
	scaleY := float64(targetH) / float64(srcH)
	scale := scaleX
	if crop != 0 && scaleY > scale {
		scale = scaleY
	} else if crop == 0 && height > 0 {
		scale = scaleY
	}
	resized, err := purevipsgenResize(in, scale)
	if err != nil {
		return nil, err
	}
	if crop == 0 {
		return resized, nil
	}
	left := (vipsImageWidth(resized) - width) / 2
	top := (vipsImageHeight(resized) - targetH) / 2
	if left < 0 { left = 0 }
	if top < 0 { top = 0 }
	out, err := purevipsgenExtractArea(resized, left, top, width, targetH)
	clearImage(resized)
	return out, err
}

func vipsEmbedWithBackground(in vipsImageRef, x int, y int, width int, height int, r int, g int, b int, a int) (vipsImageRef, error) {
	bands := vipsImageBands(in)
	if bands <= 0 {
		bands = 3
	}
	values := make([]float64, bands)
	base := []int{r, g, b, a}
	for i := range values {
		if i < len(base) {
			values[i] = float64(base[i])
		}
	}
	bg, err := purevipsgenBlackWithOptions(width, height, bands)
	if err != nil {
		return nil, err
	}
	coloured, err := purevipsgenLinear(bg, []float64{1}, values)
	clearImage(bg)
	if err != nil {
		return nil, err
	}
	out, err := purevipsgenInsert(coloured, in, x, y)
	clearImage(coloured)
	if err != nil {
		return nil, err
	}
	return out, nil
}

