func purevipsgenImageWriteToMemory(in vipsImageRef) ([]byte, error) {
	var length uintptr
	var f func(vipsImageRef, *uintptr) unsafe.Pointer
	registerVipsFunc(&f, "vips_image_write_to_memory")
	buf := f(in, &length)
	if buf == nil { return nil, handleVipsError() }
	defer gFree(buf)
	return append([]byte(nil), unsafe.Slice((*byte)(buf), int(length))...), nil
}

func purevipsgenImageWriteToBuffer(in vipsImageRef, suffix string) ([]byte, error) {
	var buf unsafe.Pointer
	var length uintptr
	var f func(vipsImageRef, string, *unsafe.Pointer, *uintptr, ...any) int32
	registerVipsFunc(&f, "vips_image_write_to_buffer")
	if f(in, cString(suffix), &buf, &length, uintptr(0)) != 0 { return nil, handleVipsError() }
	return bufferToBytes(buf, length), nil
}

func formatSaveSuffix(ext string, options []string) string {
	if len(options) == 0 { return ext }
	return ext + "[" + strings.Join(options, ",") + "]"
}

func cGoString(ptr unsafe.Pointer) string {
	if ptr == nil {
		return ""
	}
	var n uintptr
	for *(*byte)(unsafe.Add(ptr, n)) != 0 {
		n++
	}
	return string(unsafe.Slice((*byte)(ptr), n))
}

