func vipsImageGetFields(in vipsImageRef) (fields []string) {
	var f func(vipsImageRef) unsafe.Pointer
	registerVipsFunc(&f, "vips_image_get_fields")
	out := f(in)
	if out == nil { return nil }
	defer func() { var freev func(unsafe.Pointer); registerVipsFunc(&freev, "g_strfreev"); freev(out) }()
	for i := uintptr(0); ; i++ {
		ptr := *(*unsafe.Pointer)(unsafe.Add(out, i*unsafe.Sizeof(uintptr(0))))
		if ptr == nil { break }
		fields = append(fields, cGoString(ptr))
	}
	return fields
}
